    <br />
    <div id="saves">
      <template v-for="(category, catIndex) in categories" :key="catIndex">
        <div 
          class="saves category-header" 
          :style="category.styles"
          @click="toggleCategory(catIndex)"
        >
          <span>{{ category.name }}<span v-if="displays[catIndex]"> ▼</span><span v-else> ▶</span></span>
        </div>
        <br /><br />
        <div v-show="displays[catIndex]">
          <template v-for="(save, saveIndex) in category.saves" :key="saveIndex">
            <div class="saves" v-if="save.name">
              <span style="font-size: 20px">{{ save.name }}</span><br />
              <span style="font-size: 16px; font-style: italic">{{ save.desc }}</span><br />
              <span style="font-size: 12px">由{{ save.author }}上传</span><br />
              <button class="btn" @click="copySave(catIndex, saveIndex)">粘贴至剪贴板</button>
              <button class="btn" @click="downloadSave(catIndex, saveIndex)">以.txt形式保存</button>
            </div>
            <br /><br />
          </template>
        </div>
      </template>
    </div>
    <br />
    <button class="btn" @click="goBack">返回</button>
  </div>
</template>

<script setup>
import { defineProps, defineEmits, reactive, ref } from 'vue'

const props = defineProps({
  player: Object,
  v: Object
})

const emit = defineEmits(['switchPage'])

const displays = reactive(Array(10).fill(false))

function toggleCategory(index) {
  displays[index] = !displays[index]
}

function goBack() {
  emit('switchPage', 'p0_3')
}

function copySave(catIndex, saveIndex) {
  const save = categories[catIndex].saves[saveIndex]
  navigator.clipboard.writeText(save.data).then(() => {
    alert('存档已复制到剪贴板！')
  }).catch(() => {
    alert('复制失败，请手动复制')
  })
}

function downloadSave(catIndex, saveIndex) {
  const save = categories[catIndex].saves[saveIndex]
  const str = save.data
  const file = new Blob([str], { type: 'text/plain' })
  const url = window.URL || window.webkitURL
  const a = document.createElement('a')
  a.href = url.createObjectURL(file)
  a.download = save.name + '.txt'
  a.click()
}

